          data['case_subtype']!,
          _caseSubtypeMeta,
        ),
      );
    }
    if (data.containsKey('saami_doc')) {
      context.handle(
        _saamiDocMeta,
        saamiDoc.isAcceptableOrUnknown(data['saami_doc']!, _saamiDocMeta),
      );
    }
    return context;
  }

