    }
    if (data.containsKey('incline_angle_deg')) {
      context.handle(
        _inclineAngleDegMeta,
        inclineAngleDeg.isAcceptableOrUnknown(
          data['incline_angle_deg']!,
          _inclineAngleDegMeta,
        ),
      );
    }
    if (data.containsKey('atmosphere_preset_id')) {
      context.handle(
        _atmospherePresetIdMeta,
        atmospherePresetId.isAcceptableOrUnknown(
          data['atmosphere_preset_id']!,
          _atmospherePresetIdMeta,
        ),
      );
    }
    return context;
  }

